export type BrowserData = {
  coverage: number;
  id: string;
  name: string;
  versions: {
    [version: string]: number;
  };
}

export type BrowsersDataReturnType = {
  browsers: BrowserData[];
  config: string;
  coverage: number;
  lint: { id: string; message: string; fixed?: string }[];
  region?: string | null;
  updated: number;
  versions: { browserslist: string; caniuse: string };
}
